import {ExactChecker} from "@/Composables/Checkers/ExactChecker"
import {stripFirstCharacter, stripLastCharacter} from "@/Composables/useCheckers"

export function CoordChecker(options) {
	// TODO: coordchecker is by default using exactChecker. Might also be good to use nb checker

	return {
		name: "coord",
		format: () => "CoordonnĂ©es d'un point sous la forme \\((a;b)\\)",
		check: (expectedAnswer, answer = []) => {
			if (expectedAnswer === answer) {
				return {
					result: true,
					message: ""
				}
			}

			// Manque les parenthĂ¨ses
			if (answer[0] !== "(" || answer[answer.length - 1] !== ")") {
				return {
					result: false,
					message: "des coordonnĂ©es commencent et se terminent par des parenthĂ¨ses"
				}
			}

			// On rĂ©cupĂ¨re les valeurs
			let values = answer.split(";"),
				expectedValues = expectedAnswer.split(";")

			if (values.length === 1) {
				return {
					result: false,
					message: "des coordonnĂ©es ont au moins deux valeurs, sĂ©parĂ©es par un \\(;\\)"
				}
			}

			if (values.length !== expectedValues.length) {
				return {
					result: false,
					message: "la dimension de la coordonnĂ©es ne correspond pas"
				}
			}

			// remove the parentese from the first and last value.
			values[0] = stripFirstCharacter(values[0])
			values[values.length - 1] = stripLastCharacter(values[values.length - 1])

			if (expectedValues[0].startsWith("(")) {
				expectedValues[0] = stripFirstCharacter(expectedValues[0])
			}

			if (expectedValues[expectedValues.length - 1].endsWith(")")) {
				expectedValues[expectedValues.length - 1] = stripLastCharacter(expectedValues[expectedValues.length - 1])
			}


			let eChecker = ExactChecker(options)
			for (let i = 0; i < values.length; i++) {
				let result = eChecker.check(expectedValues[i], values[i])
				if (!result.result) {
					return {
						result: false,
						message: `la ${i === 0 ? "1Ă¨re" : (i + 1) + "Ă¨me"} coordonnĂ©e n'est pas juste.<br>${result.message}`
					}
				}
			}

			// tous les tests sont passĂ©s ! La rĂ©ponse est donc juste
			return {
				result: true,
				message: ""
			}
		}
	}
}
