import {PiMath} from "pimath/esm"

export function FractionChecker(options){
	if(options===undefined){options = []}

	const expectReduced = options.includes("r") || options.includes("reduced")

	return {
		name: "fraction",
		format: () => {
			let opts = []
			if (expectReduced) {
				opts.push("rĂ©duite")
			}

			return `rĂ©ponse sous forme de fraction ${opts.join(",")}`
		},
		check: (expectedAnswer, answer = []) => {
			// Le rĂ©sultat est exactement ce qui est demandĂ©
			if(answer===expectedAnswer){
				return {
					result: true,
					message: ""
				}
			}

			let FAnswer, FExpected

			try{
				FAnswer = new PiMath.Fraction(answer)
				FExpected = new PiMath.Fraction(expectedAnswer)
			}catch{
				return {
					result: false,
					message: "La fraction n'est pas formatĂ©e correctement."
				}
			}

			if(FAnswer.isNotEqual(FExpected)){
				return {
					result: false,
					message: "La rĂ©ponse donnĂ©e n'est pas juste."
				}
			}

			if(FAnswer.denominator<0){
				return {
					result: false,
					message: "Le dĂ©nominateur doit ĂŞtre positif."
				}
			}

			if(!FAnswer.isReduced() && expectReduced){
				return {
					result: false,
					message: "La fraction n'est pas rĂ©duite."
				}
			}


			return {
				result: true,
				message: ""
			}
		}
	}

}
