import {NumberChecker} from "@/Composables/Checkers/NumberChecker"

export function ScientificChecker(options) {
	return {
		name: "scientific",
		format: () => {
			if (isNaN(options[0])) {
				return "rĂ©ponse en notation scientifique"
			} else {
				return `rĂ©ponse en notation scientifique Ă  ${options[0]} chiffre(s) significatif(s)`
			}
		},
		check: (expectedAnswer, answer = []) => {
			// Le rĂ©sultat est exactement ce qui est demandĂ©
			if (answer.toString() === expectedAnswer.toString()) {
				return {
					result: true,
					message: ""
				}
			}

			// On vĂ©rifie que le format est bien de type scientifique.
			const PS = +(answer.split("*")[0]),
				OG = +(answer.split("10^")[1] || 0),
				ePS = +(expectedAnswer.split("*")[0]),
				eOG = +(expectedAnswer.split("10^")[1] || 0)

			if (!answer.includes("*10^")) {
				return {
					result: false,
					message: "le format de rĂ©ponse n'est pas une notation scientifique."
				}
			}

			// On vĂ©rifie la partie significative
			if (PS < 1 || PS >= 10) {
				return {
					result: false,
					message: "la partie significative n'est pas entre 1 et 10 (non compris)"
				}
			}

			if (PS !== ePS) {
				return {
					result: false,
					message: "erreur dans la partie significative: " + new NumberChecker(options).check(ePS, PS).message
				}
			}


			// On vĂ©rifie l'ordre de grandeur.
			if (OG !== eOG) {
				return {
					result: false,
					message: "l'ordre de grandeur n'est pas juste.."
				}
			}


			// Il n'y a pas d'option -> le rĂ©sultat ne peut pas ĂŞtre validĂ©.
			if (options.length === 0) {
				return {
					result: false,
					message: " ? "
				}
			}

			// Nombre de dĂ©cimales souhaitĂ©es
			const nbDecimales = +options[0]
			// Nomber de dĂ©cimale de la rĂ©ponse
			let crtDecimales = answer.toString().split(".")

			// Le nombre de chiffres aprĂ¨s la virgule n'est pas juste
			if (crtDecimales.length === 1 || crtDecimales[1].length !== nbDecimales) {
				return {
					result: false,
					message: `Il faut ${nbDecimales} chiffre(s) aprĂ¨s la virgule.`
				}
			}

			// Le dernier chiffre n'est pas juste - il s'agit peut ĂŞtre d'un problĂ¨me d'arrondi ?
			if (crtDecimales[crtDecimales.length - 1] - expectedAnswer.toString()[expectedAnswer.toString().length - 1] === 1) {
				return {
					result: false,
					message: "Peut ĂŞtre un problĂ¨me d'arrondi ?"
				}
			}
		}

	}

}
